INSERT INTO "public"."payment_instructions" ("id", "payment_method_id", "title", "content", "sort_order", "created_at") VALUES
(1, 2, 'Pembayaran via m-BCA', '<ol><li>Buka aplikasi BCA Mobile dan login.</li><li>Pilih menu <strong>m-Transfer</strong> > <strong>BCA Virtual Account</strong>.</li><li>Masukkan nomor Virtual Account yang tertera di atas dan klik <strong>Send</strong>.</li><li>Masukkan PIN Anda untuk mengotorisasi transaksi.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(2, 2, 'Pembayaran via KlikBCA Individual', '<ol><li>Login ke KlikBCA Individual.</li><li>Pilih <strong>Transfer</strong>, lalu pilih <strong>Transfer ke BCA Virtual Account</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Pilih Lanjutkan untuk memproses pembayaran.</li><li>Masukkan RESPON KEYBCA APPLI 1 yang ditunjukkan pada Token BCA Anda, lalu klik tombol Kirim.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(3, 2, 'Pembayaran via ATM BCA', '<ol><li>Masukkan kartu ATM BCA dan PIN Anda.</li><li>Pilih menu <strong>Transaksi Lainnya</strong>.</li><li>Pilih <strong>Transfer</strong>.</li><li>Pilih <strong>Ke BCA Virtual Account</strong>.</li><li>Masukkan Nomor Virtual Account, lalu tekan Benar.</li><li>Verifikasi detail Virtual Account lalu masukkan jumlah yang akan ditransfer dan pilih Benar untuk mengonfirmasi.</li></ol>', 3, '2026-04-19 01:39:51.048594+00'),
(4, 3, 'Pembayaran via Livin’ by Mandiri', '<ol><li>Login ke aplikasi Livin’ by Mandiri.</li><li>Pilih <strong>Transfer Rupiah</strong> > <strong>Transfer ke penerima baru</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Masukkan atau konfirmasi jumlah pembayaran.</li><li>Klik Lanjut.</li><li>Masukkan MPIN.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(5, 3, 'Pembayaran via ATM Mandiri', '<ol><li>Masukkan Kartu ATM.</li><li>Pilih bahasa yang diinginkan.</li><li>Masukkan PIN ATM.</li><li>Pilih <strong>BAYAR/BELI</strong> > <strong>MULTI PAYMENT</strong>.</li><li>Masukkan kode perusahaan 88608 (XENDIT), lalu tekan BENAR.</li><li>Masukkan nomor Virtual Account, lalu tekan BENAR.</li><li>Masukkan jumlah pembayaran, lalu tekan BENAR.</li><li>Konfirmasi detail pembayaran.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(6, 6, 'Pembayaran via BRI Mobile (BRIMO)', '<ol><li>Login ke aplikasi BRI Mobile Banking.</li><li>Pilih <strong>Pembayaran</strong> > <strong>Briva</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Masukkan jumlah pembayaran.</li><li>Masukkan PIN.</li><li>Tekan Kirim.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(7, 6, 'Pembayaran via ATM BRI', '<ol><li>Masukkan Kartu ATM.</li><li>Pilih bahasa yang diinginkan.</li><li>Masukkan PIN ATM.</li><li>Pilih <strong>Menu Lainnya</strong> > <strong>Pembayaran</strong> > <strong>Pembayaran Lainnya</strong> > <strong>BRIVA</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Masukkan jumlah pembayaran.</li><li>Konfirmasi detail pembayaran dan tekan YA.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(8, 7, 'Pembayaran via BNI Mobile Banking', '<ol><li>Login ke aplikasi BNI Mobile Banking.</li><li>Klik <strong>Transfer</strong> > <strong>Virtual Account Billing</strong>, lalu pilih rekening debet.</li><li>Masukkan nomor Virtual Account.</li><li>Jumlah pembayaran akan ditampilkan di layar.</li><li>Konfirmasi informasi pembayaran.</li><li>Masukkan password transaksi.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(9, 7, 'Pembayaran via BNI Internet Banking', '<ol><li>Login ke internet banking BNI.</li><li>Klik <strong>Transfer</strong> > <strong>Virtual Account Billing</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Pilih rekening sumber dana.</li><li>Jumlah pembayaran akan ditampilkan di layar.</li><li>Masukkan kode token autentikasi.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(10, 7, 'Pembayaran via ATM BNI', '<ol><li>Masukkan Kartu ATM.</li><li>Pilih bahasa yang diinginkan.</li><li>Masukkan PIN ATM.</li><li>Pilih <strong>Menu Lain</strong> > <strong>Transfer</strong>.</li><li>Pilih jenis rekening sumber dana.</li><li>Pilih <strong>Virtual Account Billing</strong> dan masukkan nomor Virtual Account.</li><li>Jumlah pembayaran akan ditampilkan di layar.</li><li>Konfirmasi informasi pembayaran.</li></ol>', 3, '2026-04-19 01:39:51.048594+00'),
(11, 8, 'Pembayaran via BJB Mobile', '<ol><li>Buka aplikasi BJB Mobile.</li><li>Masukkan User ID dan Password.</li><li>Pilih <strong>Virtual Account</strong>.</li><li>Pilih jenis rekening sumber dana (misal: Tabungan).</li><li>Masukkan Nomor Virtual Account.</li><li>Konfirmasi detail transaksi Anda.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(12, 8, 'Pembayaran via BJB Net', '<ol><li>Buka BJB Net.</li><li>Masukkan User ID dan Password.</li><li>Pilih <strong>Virtual Account</strong>.</li><li>Pilih jenis rekening sumber dana.</li><li>Masukkan Nomor Virtual Account.</li><li>Konfirmasi detail transaksi Anda.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(13, 8, 'Pembayaran via ATM BJB', '<ol><li>Masukkan kartu ATM BJB dan PIN Anda.</li><li>Pilih Menu <strong>Transaksi Lainnya</strong>.</li><li>Pilih <strong>Virtual Account</strong>.</li><li>Pilih jenis rekening sumber dana.</li><li>Masukkan Nomor Virtual Account.</li><li>Konfirmasi detail transaksi Anda.</li></ol>', 3, '2026-04-19 01:39:51.048594+00'),
(14, 9, 'Pembayaran via BNC Mobile / Neobank', '<ol><li>Login ke aplikasi BNC Mobile atau Neobank.</li><li>Klik <strong>Hematpay VA & QRIS</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Masukkan jumlah pembayaran.</li><li>Konfirmasi informasi pembayaran.</li><li>Masukkan PIN.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(15, 9, 'Pembayaran via ATM BNC', '<ol><li>Masukkan Kartu ATM.</li><li>Pilih bahasa yang diinginkan.</li><li>Masukkan PIN ATM.</li><li>Pilih <strong>Pembayaran VA</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Masukkan jumlah pembayaran.</li><li>Konfirmasi informasi pembayaran.</li><li>Masukkan PIN.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(16, 4, 'Pembayaran via BYOND BSI', '<ol><li>Login ke BYOND BSI.</li><li>Pilih <strong>Bayar & Beli</strong>.</li><li>Cari Xendit, Pilih Prefix VA: 9347 atau 9655.</li><li>Masukkan kode VA (tanpa prefix).</li><li>Masukkan PIN.</li><li>Konfirmasi detail pembayaran.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(17, 4, 'Pembayaran via BSI Internet Banking', '<ol><li>Login ke BSI Net.</li><li>Klik <strong>Pembayaran</strong>.</li><li>Pilih sumber dana.</li><li>Klik <strong>Institusi</strong>.</li><li>Masukkan Xendit sebagai nama institusi (kode 9347).</li><li>Masukkan nomor Virtual Account.</li><li>Konfirmasi detail pembayaran.</li><li>Masukkan kode token autentikasi.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(18, 4, 'Pembayaran via ATM BSI', '<ol><li>Masukkan Kartu ATM BSI.</li><li>Pilih bahasa yang diinginkan.</li><li>Masukkan PIN ATM.</li><li>Pilih <strong>Pembayaran/Pembelian</strong> > <strong>Institusi</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Konfirmasi detail pembayaran.</li></ol>', 3, '2026-04-19 01:39:51.048594+00'),
(19, 10, 'Pembayaran via OCTO Mobile', '<ol><li>Buka OCTO Mobile dan masukkan User ID dan Password.</li><li>Pilih menu <strong>Transfer</strong> lalu pilih <strong>CIMB Niaga Lainnya</strong>.</li><li>Masukkan Nomor Virtual Account pada menu Input Baru.</li><li>Masukkan jumlah pembayaran.</li><li>Konfirmasi transaksi dan masukkan password/PIN Anda.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(20, 10, 'Pembayaran via ATM CIMB Niaga', '<ol><li>Masukkan Kartu ATM Anda.</li><li>Pilih bahasa yang diinginkan.</li><li>Masukkan PIN ATM.</li><li>Pilih menu <strong>Transfer</strong> lalu pilih <strong>CIMB Niaga Lainnya</strong>.</li><li>Masukkan Nomor Virtual Account.</li><li>Masukkan jumlah pembayaran.</li><li>Konfirmasi transaksi Anda.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(21, 10, 'Pembayaran via OCTO Clicks', '<ol><li>Login ke OCTO Clicks.</li><li>Pilih menu <strong>Transfer</strong> lalu pilih <strong>CIMB Niaga Lainnya</strong>.</li><li>Masukkan Nomor Virtual Account pada menu Input Baru.</li><li>Masukkan jumlah pembayaran.</li><li>Konfirmasi transaksi dan masukkan password Anda.</li></ol>', 3, '2026-04-19 01:39:51.048594+00'),
(22, 11, 'Pembayaran via MDIN (Mobile Muamalat)', '<ol><li>Login ke aplikasi MDIN.</li><li>Pilih <strong>Beli/Bayar</strong> > <strong>Beli/Bayar Tagihan</strong> > <strong>Virtual Account</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Masukkan jumlah pembayaran.</li><li>Konfirmasi detail pembayaran.</li><li>Masukkan PIN.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(23, 11, 'Pembayaran via Muamalat Internet Banking', '<ol><li>Login ke Muamalat Internet Banking.</li><li>Klik <strong>Pembayaran</strong> > <strong>Virtual Account</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Masukkan jumlah pembayaran.</li><li>Konfirmasi detail pembayaran.</li><li>Masukkan PIN.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(24, 11, 'Pembayaran via ATM Muamalat', '<ol><li>Masukkan Kartu ATM.</li><li>Pilih bahasa yang diinginkan.</li><li>Masukkan PIN ATM.</li><li>Pilih <strong>Pembayaran</strong> > <strong>Virtual Account</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Masukkan jumlah pembayaran.</li><li>Konfirmasi detail pembayaran.</li><li>Masukkan PIN.</li></ol>', 3, '2026-04-19 01:39:51.048594+00'),
(25, 12, 'Pembayaran via Permata Mobile App', '<ol><li>Login ke aplikasi PermataMobile X.</li><li>Pilih <strong>Pembayaran Tagihan</strong> > <strong>Virtual Account</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Masukkan token autentikasi.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(26, 12, 'Pembayaran via PermataNet', '<ol><li>Login ke PermataNet.</li><li>Pilih <strong>Pembayaran Tagihan</strong> > <strong>Virtual Account</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Konfirmasi detail pembayaran.</li><li>Masukkan kode respon token SMS.</li></ol>', 2, '2026-04-19 01:39:51.048594+00'),
(27, 12, 'Pembayaran via ATM Permata', '<ol><li>Masukkan Kartu ATM.</li><li>Pilih bahasa yang diinginkan.</li><li>Masukkan PIN ATM.</li><li>Pilih <strong>Transaksi Lainnya</strong> > <strong>Pembayaran</strong> > <strong>Pembayaran Lainnya</strong> > <strong>Virtual Account</strong>.</li><li>Masukkan nomor Virtual Account.</li><li>Konfirmasi detail pembayaran.</li><li>Masukkan PIN.</li></ol>', 3, '2026-04-19 01:39:51.048594+00'),
(28, 13, 'Pembayaran via Alfamart', '<ol><li>Kunjungi cabang ALFAMART, Alfamidi, Dan+Dan, atau Lawson terdekat sebelum waktu kedaluwarsa habis.</li><li>Beri tahu kasir bahwa Anda ingin melakukan pembayaran "Yayasan Peduli Sesama" via Xendit atau tunjukkan barcode pembayaran.</li><li>Tunjukkan kode pembayaran/barcode ke kasir dan konfirmasikan jumlahnya.</li><li>Lakukan pembayaran sesuai dengan nominal tagihan.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(29, 14, 'Pembayaran via Indomaret', '<ol><li>Kunjungi cabang INDOMARET terdekat sebelum waktu kedaluwarsa habis.</li><li>Beri tahu kasir untuk melakukan pembayaran Xendit.</li><li>Sebutkan kode pembayaran ke Kasir atau tunjukkan barcode.</li><li>Konfirmasikan jumlah tagihan kepada kasir lalu lakukan pembayaran.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(30, 1, 'Pembayaran dengan Aplikasi Gojek / GoPay', '<ol><li>Buka aplikasi Gojek atau dompet digital Anda.</li><li>Pilih menu <strong>Bayar / Scan</strong>.</li><li>Scan QR Code yang tampil di layar atau upload dari galeri.</li></ol>', 1, '2026-04-19 01:39:51.048594+00'),
(31, 5, 'Transfer via ATM / M-Banking BSI', '<ol><li>Login ke aplikasi BSI Mobile atau datangi ATM BSI terdekat.</li><li>Pilih menu <strong>Transfer</strong> > <strong>Antar Rekening BSI</strong>.</li><li>Masukkan rekening tujuan: <strong>7123456789</strong>.</li><li>Pastikan nama penerima: <strong>Yayasan Peduli Sesama</strong>.</li><li>Transfer dana sesuai dengan nominal tagihan hingga 3 digit terakhir.</li><li>Simpan bukti transfer dan unggah pada halaman status.</li></ol>', 1, '2026-04-19 01:39:51.048594+00');